INSERT INTO `board` VALUES (1,9,'notice','[안내] BankScope AI 큐매니저 및 지능형 챗봇 서비스 고도화 안내','안녕하세요. BankScope 운영팀입니다.\n\n더욱 신속하고 정확한 금융 업무 처리를 위해 AI 기반의 큐매니저 및 맞춤형 챗봇 엔진 업데이트가 성공적으로 적용되었습니다.\n\n주요 업데이트 내용:\n\nAI 큐매니저 오차율 개선: 실시간 대기 인원 및 업무 복잡도를 분석하여 예상 대기 시간을 기존 대비 15% 더 정확하게 예측합니다.\n\n지능형 금융 챗봇 고도화: 자연어 처리(NLP) 모델 개선으로 복잡한 여신/수신 상품에 대한 맞춤형 상담 기능이 강화되었습니다.\n\n앞으로도 안전하고 스마트한 금융 Mini-ERP 환경을 제공하기 위해 최선을 다하겠습니다. 감사합니다.',0,'2026-06-04 14:30:05','2026-06-04 14:30:05');
INSERT INTO `board` VALUES (2,9,'notice','[보안] 데이터 자산 보호를 위한 차세대 대칭키 암호화 알고리즘 적용 안내','안녕하세요. BankScope 최고관리자입니다.\n\n고객님의 소중한 개인정보 및 금융 거래 데이터를 안전하게 보호하기 위해, 전체 시스템의 암호화 모듈을 차세대 AES-256 대칭키 알고리즘 기반으로 전면 업그레이드하였습니다.\n\n적용 대상: 주민등록번호, 계좌 비밀번호, 금융 자산 데이터 전체\n\n기대 효과: 데이터베이스 해킹 및 외부 유출 시에도 원천적으로 복호화가 불가능하도록 엔드투엔드(E2E) 보안 체계를 확립했습니다.\n\nBankScope는 최고 수준의 금융 보안 표준을 준수합니다.',0,'2026-06-04 14:30:20','2026-06-04 14:30:20');
INSERT INTO `board` VALUES (3,9,'notice','[공지] 2026 상반기 BankScope 수신 및 여신 신규 금융 상품 출시 안내','안녕하세요. BankScope 최고관리자입니다.\n\n우리 은행을 이용해 주시는 개인 및 기업 고객 여러분의 효율적인 자금 운용을 지원하기 위해, 2026년 상반기 신규 금융 상품 라인업이 정식 출시되었습니다.\n\n핵심 상품 라인업 안내:\n\n청년 희망적금 (개인): 만 19세~34세 청년 전용, 정부 지원 포함 최고 연 6.00% 제공 (월 최대 50만 원)\n\n기업 정기예금 (법인/사업자): 최대 20억 원까지 예치 가능한 고액 정기예금 (최고 연 3.80%)\n\n소상공인 대출 (공통): 자영업자를 위한 정책자금 연계형 시설/운전자금 대출 (최저 연 4.00%, 최대 5억 원 지원)\n\n상세한 가입 자격 및 기간별 우대금리 조건은 상단의 \'금융 상품 관리\' 메뉴에서 확인하실 수 있습니다. 고객 여러분의 많은 관심 부탁드립니다.',0,'2026-06-04 14:30:38','2026-06-04 14:30:38');
INSERT INTO `board` VALUES (4,9,'notice','[안내] BankScope 입출금 통장 라인업 금리 및 이체 서비스 안내','안녕하세요. BankScope 운영팀입니다.\n\n일상적인 금융 거래와 기업의 수시 자금 관리를 위한 입출금 통장 2종의 기본 금리 및 혜택을 안내해 드립니다.\n\n대상 상품 안내:\n\n개인 입출금 통장 (INDIVIDUAL): 급여이체, 공과금 자동납부 실적 충족 시 최고 연 0.50% 적용.\n\n자유입출금 통장 (ALL): 개인과 법인 모두 제한 없이 가입 가능하며, 모바일 뱅킹 연계 시 최고 연 1.00% 금리 제공.\n\n본 입출금 통장 상품들은 인터넷 및 모바일 뱅킹을 통한 이체 수수료가 전면 면제되오니, 자금 이체가 빈번한 기업 회원 및 개인 고객님들께서는 적극 활용해 보시기 바랍니다.',0,'2026-06-04 14:30:56','2026-06-04 14:30:56');
INSERT INTO `board` VALUES (5,9,'notice','[시스템] \'BankScope 신용대출\' AI 기반 무담보 고속 심사 엔진 적용 공지','안녕하세요. BankScope 기술운영팀입니다.\n\n개인 고객을 대상으로 하는 \'BankScope 신용대출\' 상품에 AI 신용평가 알고리즘(Random Forest) 엔진이 정식 탑재되었습니다.\n\n적용 상품: BankScope 신용대출 (개인 전용)\n\n주요 변경 사항: 별도의 복잡한 서류 제출이나 담보 없이, 신용등급 및 ERP 재무 데이터를 AI가 분석하여 최대 5,000만 원 한도 내에서 대출 가능 여부와 금리(연 5.50% ~ 15.00%)를 실시간으로 빠르게 산출합니다.\n\n더욱 고도화된 지능형 금융 ERP 서비스를 통해 영업점 방문 없이 비대면으로 신속한 자금 조달을 경험해 보세요.',0,'2026-06-04 14:31:14','2026-06-04 14:31:14');
INSERT INTO `board` VALUES (6,9,'event','[이벤트] AI가 추천하는 맞춤형 금융 상품 구독하고 우대 금리 +1.0% 받자!','🎉 내 자산 현황에 딱 맞는 상품은 무엇일까?\n\nBankScope의 똑똑한 AI 모델이 고객님의 거래 패턴과 재무 상태를 분석하여 가장 최적의 금융 상품을 추천해 드립니다. 지금 AI 추천 상품을 구독하고 특별한 혜택을 만나보세요!\n\n이벤트 기간: 2026년 5월 19일 ~ 2026년 6월 30일\n\n참여 방법: > 1. 메인 대시보드에서 \'AI 맞춤 상품 추천\' 확인\n2. 추천된 예/적금 상품 \'구독하기\' 버튼 클릭\n\n이벤트 혜택: 이벤트 기간 내 구독 고객 전원 우대 금리 연 1.0% 즉시 추가 적용',0,'2026-06-04 14:31:41','2026-06-04 14:31:41');
INSERT INTO `board` VALUES (7,9,'event','[이벤트] 봄맞이 종잣돈 마련 프로젝트! 청년 희망적금 & 자유적금 우대 혜택','🎉 BankScope와 함께 시작하는 자산 형성 엔진!\n\n매월 든든하게 저축하고 최고 금리 혜택을 누릴 수 있는 적금 상품 가입 이벤트를 진행합니다.\n\n이벤트 대상 상품:\n\nBankScope 청년 희망적금: 최고 연 6.00% (청년층 한정, 월 최대 50만 원)\n\nBankScope 자유적금: 최고 연 5.00% (매월 자유 납입, 월 최대 300만 원)\n\n특별 혜택: 이벤트 기간 내 위 적금 상품을 12개월 이상 기간으로 신규 가입한 고객 중 추첨을 통해 100명에게 베이커리 모바일 쿠폰을 지급합니다.\n\n기간: 2026년 5월 19일 ~ 2026년 6월 30일\n\n지금 \'적금 가입\' 메뉴에서 나의 첫 희망 자금을 설계해 보세요!',0,'2026-06-04 14:31:55','2026-06-04 14:31:55');
INSERT INTO `board` VALUES (8,9,'event','[기업] 소상공인 대출 & 기업 정기적금 연계 우대금리 프로모션','중소기업 및 소상공인 대표님들의 성공적인 비즈니스를 지원하기 위해, BankScope가 든든한 상생 금융 프로모션을 준비했습니다.\n\n대상 상품 및 혜택:\n\nBankScope 소상공인 대출: 최저 연 4.00% (최대 5억 원 한도), 정책자금 매칭 성공 시 대출 금리 추가 인하 혜택.\n\nBankScope 기업 정기적금: 소상공인/중소기업 전용 세금 우대 적금 (최고 연 4.00%, 최대 1억 원까지 납입 가능).\n\n연계 리워드: 대출 상품 이용 고객이 \'기업 정기적금\'에 동시 가입하는 경우, 적금 만기 시 법인 자금 관리 리포트 기능 정기 구독권을 6개월간 무료로 제공합니다.\n\n스마트한 기업 자금 운용, 이제 BankScope 지점 방문을 통해 행원과 함께 효율을 극대화하세요.',0,'2026-06-04 14:32:09','2026-06-04 14:32:09');
INSERT INTO `board` VALUES (9,9,'event','[챌린지] 개인·법인 공통! \'BankScope 목표 적금\' 달성하고 추가 리워드 받자','🎯 개인도, 기업도 누구나 참여 가능한 저축 챌린지!\n\n금액과 목표 기간(6개월~36개월)을 자유롭게 설정하고, 성공적인 만기를 달성할 수 있도록 돕는 \'BankScope 목표 적금\' 출시 기념 챌린지를 시작합니다.\n\n이벤트 상품: BankScope 목표 적금 (가입 금액: 1만 원 ~ 200만 원)\n\n기본 금리: 연 3.50% ~ 최고 연 4.50%\n\n챌린지 혜택: > 설정한 목표 금액을 중도 해지 없이 100% 납입 완료하여 만기 달성 시, 목표 달성 축하 우대 금리 최고 연 4.50% 보장 및 기업/개인 회원별 맞춤형 세무/재무 컨설팅 리포트 1회권을 무료로 발급해 드립니다.\n\n지금 즉시 목표를 설정하고 똑똑하게 자산을 불려보세요!',0,'2026-06-04 14:32:23','2026-06-04 14:32:23');
